const topics = [
  'How AI chatbots help HVAC companies capture leads after hours when homeowners search for emergency repairs',
  'Why missed calls cost local plumbers thousands — and how an AI assistant fixes it 24/7',
  'How dental offices use AI chat to pre-qualify patients and fill appointment slots automatically',
  'The ROI of 24/7 AI for local service businesses: stop losing leads to competitors who answer faster',
  'Real estate agents: how AI chatbots pre-qualify buyer leads so you only talk to serious clients',
  'Landscaping companies: turn website visitors into booked jobs with an AI that qualifies and follows up',
  'Auto repair shops: how AI chat captures every online inquiry even when the front desk is slammed'
];
const day = new Date().getDay();
const topic = topics[(day - 1 + 7) % topics.length];
return [{json: {topic}}];

const body = $input.item.json;
const text = body.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';
if (!text) throw new Error('No content from Gemini: ' + JSON.stringify(body));
return [{json: {postText: text}}];
